import { useMemo } from "react"

const ChartDraw = (props) => {
    const width = 800;
    const height = 400;

    const margin = {
        top: 10,
        bottom: 60,
        left: 40,
        right: 10
    };

    const boundsWidth = width - margin.left - margin.right;
    const boundsHeight = height - margin.top - margin.bottom;

    const series = useMemo(() => {
        const allSeries = [
            { isActive: props.oy[0], valueIndex: 1, color: "red", key: "max" },
            { isActive: props.oy[1], valueIndex: 0, color: "blue", key: "min" }
        ];

        return allSeries.filter(item => item.isActive);
    }, [props.oy]);

    const values = useMemo(() => {
        return series.flatMap(item =>
            props.data.map(point => point.values[item.valueIndex])
        );
    }, [props.data, series]);

    const minValue = values.length > 0 ? Math.min(...values) : 0;
    const maxValue = values.length > 0 ? Math.max(...values) : 0;
    const lowerBound = minValue === maxValue ? minValue - 1 : minValue * 0.85;
    const upperBound = minValue === maxValue ? maxValue + 1 : maxValue * 1.1;
    const yRange = upperBound - lowerBound || 1;
    const xAxisY = margin.top + boundsHeight;
    const stepX = props.data.length > 0 ? boundsWidth / props.data.length : boundsWidth;
    const bandWidth = stepX * 0.8;

    const getBandX = (index) => margin.left + index * stepX + (stepX - bandWidth) / 2;
    const getCenterX = (index) => getBandX(index) + bandWidth / 2;
    const scaleY = (value) => margin.top + boundsHeight - ((value - lowerBound) / yRange) * boundsHeight;
    const ticks = Array.from({ length: 6 }, (_, index) => lowerBound + (yRange * index) / 5);

    if (props.data.length === 0 || series.length === 0) {
        return (
            <svg viewBox={`0 0 ${width} ${height}`}>
                <text x="40" y="40">Нет данных для построения диаграммы</text>
            </svg>
        );
    }

    return (
      <svg viewBox={`0 0 ${width} ${height}`}>
        <rect
          x={ margin.left }
          y={ margin.top }
          width={ boundsWidth }
          height={ boundsHeight }
          fill="lightgrey"
        />

        <line x1={ margin.left } y1={ xAxisY } x2={ width - margin.right } y2={ xAxisY } />
        <line x1={ margin.left } y1={ margin.top } x2={ margin.left } y2={ xAxisY } />

        {ticks.map((tick, index) => {
            const y = scaleY(tick);

            return (
                <g key={ index }>
                    <line x1={ margin.left - 5 } y1={ y } x2={ margin.left } y2={ y } />
                    <text x={ margin.left - 8 } y={ y + 3 } textAnchor="end">
                        {tick.toFixed(1)}
                    </text>
                </g>
            );
        })}

        {props.data.map((item, index) => (
            <g key={ item.labelX }>
                <line x1={ getCenterX(index) } y1={ xAxisY } x2={ getCenterX(index) } y2={ xAxisY + 5 } />
                <text
                  x={ getCenterX(index) }
                  y={ height - 20 }
                  textAnchor="end"
                  transform={`rotate(-30 ${getCenterX(index)} ${height - 20})`}
                >
                    {item.labelX}
                </text>
            </g>
        ))}

        {series.map(item =>
            props.data.map((point, index) => {
                const value = point.values[item.valueIndex];

                if (props.chartType === "Столбчатая диаграмма") {
                    const innerWidth = bandWidth / series.length;
                    const x = getBandX(index) + innerWidth * series.indexOf(item);
                    const y = scaleY(value);

                    return (
                        <rect
                          key={`${item.key}-${point.labelX}`}
                          x={ x }
                          y={ y }
                          width={ innerWidth }
                          height={ xAxisY - y }
                          fill={ item.color }
                          opacity="0.75"
                        />
                    );
                }

                return (
                    <circle
                      key={`${item.key}-${point.labelX}`}
                      r="5"
                      cx={ getCenterX(index) }
                      cy={ scaleY(value) }
                      fill={ item.color }
                    />
                );
            })
        )}

      </svg>
    )
}

export default ChartDraw;
